const rawText = $json.ParsedResults[0].ParsedText || "";
const cleaned = rawText.replace(/\r/g, "").replace(/\\n/g, "\n");
const lines = cleaned.split("\n").map(l => l.trim()).filter(Boolean);

// ─── FECHA ───────────────────────────────────────────────
let invoiceDate = null;
const fechaLine = lines.find(line => line.toLowerCase().startsWith("fecha:"));
if (fechaLine) {
  const match = fechaLine.match(/(\d{2}\/\d{2}\/\d{4})/);
  if (match) invoiceDate = match[1];
}

// ─── NÚMERO DE FACTURA ───────────────────────────────────
// El OCR parte "FESF" y "447123" en líneas distintas
let invoiceNumber = null;
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  if (line.toUpperCase().includes("FACT ELECTRONICA DE VENTA:")) {
    // Intenta extraer en la misma línea
    const same = line.match(/FESF[\s\-]*(\d+)/i);
    if (same) { invoiceNumber = "FESF-" + same[1]; break; }
    // Si no, busca en las siguientes dos líneas
    for (let j = i + 1; j <= i + 2 && j < lines.length; j++) {
      const next = lines[j];
      const m = next.match(/(\d{4,})/);
      if (m) { invoiceNumber = "FESF-" + m[1]; break; }
    }
    break;
  }
}

// ─── MONTO TOTAL ─────────────────────────────────────────
// Busca la línea que tenga "$ 6.699" o similar (patrón: $ seguido de dígitos/puntos/comas)
// Prioridad: línea que contenga "$ X.XXX" después de SUB TOTAL / antes del fin
let amount = null;

// 1) Buscar línea explícita con signo $ y número (ej: "$ 6.699")
for (let i = 0; i < lines.length; i++) {
  const m = lines[i].match(/^\$\s*([\d.,]+)$/);
  if (m) { amount = m[1]; break; }
}

// 2) Si no encontró, buscar dentro de cualquier línea "$ XXXX"
if (!amount) {
  for (let i = 0; i < lines.length; i++) {
    const m = lines[i].match(/\$\s*([\d]{1,3}(?:[.,]\d{3})+(?:[.,]\d{1,2})?)/);
    if (m) { amount = m[1]; break; }
  }
}

// 3) Fallback: valor numérico en la línea justo después de "SUB TOTAL:"
if (!amount) {
  const subIdx = lines.findIndex(l => l.toLowerCase().includes("sub total:"));
  if (subIdx !== -1) {
    // Puede estar en la misma línea o en la siguiente
    const same = lines[subIdx].match(/:\s*([\d.,]+)/);
    if (same) { amount = same[1]; }
    else if (subIdx + 1 < lines.length) {
      const m = lines[subIdx + 1].match(/^[\d.,]+$/);
      if (m) amount = lines[subIdx + 1];
    }
  }
}

// ─── MÉTODO DE PAGO ───────────────────────────────────────
let paymentMethod = "";
const pagoLine = lines.find(line => line.toLowerCase().includes("tipo pago:"));
if (pagoLine) {
  const parts = pagoLine.split(":");
  if (parts.length > 1) paymentMethod = parts[1].trim();
}

// ─── NOTAS ────────────────────────────────────────────────
let notes = "No tenias notas pendientes";
const notaIndex = lines.findIndex(l => l.toLowerCase().includes("nota adicional:"));
if (notaIndex !== -1) {
  const notaParts = lines[notaIndex].split(":");
  if (notaParts.length > 1 && notaParts[1].trim()) {
    notes = notaParts[1].trim();
  } else if (notaIndex + 1 < lines.length) {
    // Toma la siguiente línea solo si no es un encabezado de sección
    const next = lines[notaIndex + 1];
    if (!next.startsWith("-") && !next.toUpperCase().includes("PRODUCTO")) {
      notes = next;
    }
  }
}

// ─── NIT / CLIENTE ───────────────────────────────────────
let clientName = "";
let clientNit = "";
const clienteLine = lines.find(l => l.toUpperCase().startsWith("CLIENTE:"));
if (clienteLine) {
  const m = clienteLine.match(/CLIENTE:\s*(.+?)\s+CC\/NIT\s*:\s*([\d]+)/i);
  if (m) { clientName = m[1].trim(); clientNit = m[2].trim(); }
}

return [{
  json: {
    InvoiceNumber: invoiceNumber,
    InvoiceDate:   invoiceDate,
    DueDate:       null,
    Amount:        amount,
    PaymentMethod: paymentMethod,
    Notes:         notes,
    ClientName:    clientName,
    ClientNit:     clientNit,
  }
}];

